input.command:
node -e "
const gt=(process.env.GITHUB_TOKEN??'').trim();
const rk=(process.env.RENDER_API_KEY??'').trim();
const gr=(process.env.GITHUB_REPO??'').trim();
console.log('GITHUB_TOKEN len:'+gt.length+' shape:'+(/^(ghp_|github_pat_)[A-Za-z0-9_]+$/.test(gt)?'OK':'BAD'));
console.log('RENDER_API_KEY len:'+rk.length+' prefix:'+rk.slice(0,4));
console.log('GITHUB_REPO='+gr);
if(!gt){console.log('TOKEN_EMPTY');process.exit(0);}
const H={Authorization:'Bearer '+gt,'User-Agent':'ivx-deploy','Accept':'application/vnd.github+json'};
(async()=>{
  const r1=await fetch('https://api.github.com/user',{headers:H});
  const b1=await r1.json().catch(()=>({}));
  console.log('GH_USER_HTTP:'+r1.status+' login:'+(b1.login??null));
  const r2=await fetch('https://api.github.com/repos/ibb142/rork-global-real-estate-invest',{headers:H});
  const b2=await r2.json().catch(()=>({}));
  console.log('GH_REPO_HTTP:'+r2.status+' full:'+(b2.full_name??null)+' perms:'+JSON.stringify(b2.permissions??null)+' default:'+(b2.default_branch??null));
})();
"

